import React, { useState } from "react";
import { UserMinus, Search, UserPlus } from "lucide-react";
import api from "../../api.js";
import "../../components/Components.css";

export default function MembersTab(props) {
  // ✅ FORCE SAFE VALUES
  const members = Array.isArray(props?.members) ? props.members : [];
  const memberDetails = Array.isArray(props?.memberDetails) ? props.memberDetails : [];
  const leadInvestigators = Array.isArray(props?.leadInvestigators) ? props.leadInvestigators : [];

  const caseId = props?.caseId;
  const isAdmin = props?.isAdmin;
  const onRefresh = props?.onRefresh;

  const [searchTerm, setSearchTerm] = useState("");
  const [searchResults, setSearchResults] = useState([]);
  const [showSearch, setShowSearch] = useState(false);

  // 🔍 SEARCH
  const handleSearch = async (e) => {
    const val = e.target.value;
    setSearchTerm(val);

    if (val.length >= 1) {
      try {
        const res = await api.get(`/users/search?q=${val}`);
        setSearchResults(Array.isArray(res?.data) ? res.data : []);
      } catch {
        setSearchResults([]);
      }
    } else {
      setSearchResults([]);
    }
  };

  // ➕ ADD MEMBER
  const handleAddMember = async (userId) => {
    if (!caseId) {
      alert("Invalid case ID");
      return;
    }

    try {
      await api.post(`/case/${caseId}/member`, { user_id: userId });
      alert("Member added successfully");
      onRefresh?.();
    } catch (err) {
      alert(err?.response?.data?.message || "Failed to add member");
    }
  };

  // ❌ REMOVE MEMBER
  const handleRemoveMember = async (userId, name) => {
    if (!window.confirm(`Remove ${name}?`)) return;

    try {
      await api.delete(`/case/${caseId}/member/${userId}`);
      alert("Member removed");
      onRefresh?.();
    } catch {
      alert("Failed to remove member");
    }
  };

  // ✅ SAFE DETAILS (CRITICAL FIX)
  let details = [];

  if (memberDetails && memberDetails.length > 0) {
    details = memberDetails;
  } else if (members && members.length > 0) {
    details = members.map((name) => ({
      name,
      role: null,
      id: null,
    }));
  }

  return (
    <div className="memberList">

      {/* ADD MEMBER */}
      {isAdmin && (
        <div>
          <button onClick={() => setShowSearch(!showSearch)}>
            <UserPlus size={15} /> Add Member
          </button>

          {showSearch && (
            <>
              <input
                value={searchTerm}
                onChange={handleSearch}
                placeholder="Search users..."
              />

              {(Array.isArray(searchResults) ? searchResults : []).map((u) => (
                <div key={u._id}>
                  {u.name}
                  <button onClick={() => handleAddMember(u._id)}>
                    Add
                  </button>
                </div>
              ))}
            </>
          )}
        </div>
      )}

      {/* MEMBERS LIST */}
      {Array.isArray(details) && details.length > 0 ? (
        details.map((member, i) => {
          const isLead = leadInvestigators.includes(member?.name);

          return (
            <div key={member?.id || i}>
              <span>{member?.name || "Unknown"}</span>
              {isLead && " ★"}

              {isAdmin && member?.id && (
                <button
                  onClick={() =>
                    handleRemoveMember(member.id, member.name)
                  }
                >
                  <UserMinus size={15} />
                </button>
              )}
            </div>
          );
        })
      ) : (
        <p>No members assigned</p>
      )}
    </div>
  );
}
